CREATE TABLE IF NOT EXISTS public.users(id UUID PRIMARY KEY,name TEXT NOT NULL,age INTEGER,weight FLOAT,height FLOAT,health_conditions TEXT[],food_preference TEXT,region TEXT,budget_preference TEXT,gender TEXT,blood_type TEXT,goal TEXT,sleep_schedule TEXT,activity_level TEXT,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());CREATE TABLE IF NOT EXISTS public.food_logs(id BIGSERIAL PRIMARY KEY,user_id UUID REFERENCES public.users(id) ON DELETE CASCADE,name TEXT NOT NULL,category TEXT NOT NULL,calories INTEGER DEFAULT 0,fat FLOAT DEFAULT 0.0,sugar FLOAT DEFAULT 0.0,protein FLOAT DEFAULT 0.0,cost FLOAT DEFAULT 0.0,notes TEXT,created_at TIMESTAMPTZ DEFAULT NOW());ALTER TABLE public.users ENABLE ROW LEVEL SECURITY;ALTER TABLE public.food_logs ENABLE ROW LEVEL SECURITY;
